SELECT COUNT(1)
  FROM TORDER_MST_ORCD_DT
 WHERE
       LAKEY = #{lakey} 

	   AND ORCD_HDKEY = #{orcd_hdkey}


	   AND (ORCD_HDKEY LIKE '%'|| #{value} || '%' OR ORCD_DTKEY LIKE '%'|| #{value} || '%' OR ORCD_DTNAME LIKE '%'|| #{value} || '%' OR ORCD_DTVALUE LIKE '%'|| #{value} || '%')

SELECT B.* FROM( SELECT ORCD_DTKEY AS FIELD1 , ORCD_DTNAME AS FIELD2 , ORCD_DTVALUE AS FIELD3, ORCD_HDKEY AS FIELD4, ORCD_DTORDER AS ORCD_DTORDER FROM TORDER_MST_ORCD_DT WHERE LAKEY = #{lakey}
AND ORCD_HDKEY = #{orcd_hdkey}
AND (ORCD_HDKEY LIKE '%'|| #{value} || '%' OR ORCD_DTKEY LIKE '%'|| #{value} || '%' OR ORCD_DTNAME LIKE '%'|| #{value} || '%' OR ORCD_DTVALUE LIKE '%'|| #{value} || '%')
) B
ORDER BY #{colName} DESC
ORDER BY #{colName} ASC
ORDER BY ORCD_DTORDER ASC
