SELECT COUNT(1) FROM ( SELECT DISTINCT A.ICKEY AS FIELD1 ,A.ICNM AS FIELD2 ,A.OWKEY AS FIELD3 ,A.ICUNITKEY AS FIELD4 ,A.UOM AS FIELD5 ,'ICUTTYPE' ||';'|| A.UOM AS FIELD5_DESC ,B.LOGGRPCD AS FIELD6 ,'LOGGRPCD' ||';'|| B.LOGGRPCD AS FIELD6_DESC ,SUM(D.AVQTY) AS AVQTY ,SUM(D.TTQTY) AS TTQTY FROM TADMIN_MST_IC A INNER JOIN TADMIN_MST_ICXCT B ON A.ICKEY = B.ICKEY LEFT OUTER JOIN TWORK_INFO_IVAT C ON A.OWKEY = C.OWKEY AND A.ICKEY = C.ICKEY AND B.CTKEY = C.CTKEY LEFT OUTER JOIN TWORK_INFO_IVATXLCXULC D ON C.CTKEY = D.CTKEY AND C.OWKEY = D.OWKEY AND C.ICKEY = D.ICKEY AND C.IVATKEY = D.IVATKEY WHERE A.CLOSDATE >= #{sysdate} AND A.DELYN = 'N'
AND A.OWKEY IN
#{OWKEY_SELECTION_VALUE}
AND A.OWKEY = #{owkey}
AND A.ACKEY = #{ackey}
AND B.CTKEY = #{ctkey}
AND (A.ICKEY LIKE '%'|| #{value} || '%' OR A.ICNM LIKE '%'|| #{value} || '%' OR A.ICUNITKEY LIKE '%'|| #{value} || '%' OR A.UOM LIKE '%'|| #{value} || '%' )
GROUP BY A.ICKEY, A.ICNM, A.OWKEY, A.ICUNITKEY, A.UOM, B.LOGGRPCD ) B

