mapper.sql:
SELECT DISTINCT A.URKEY AS FIELD1 ,A.URKEY AS FIELD1_DESC ,A.ACKEY AS FIELD2 ,B.ACNAME AS FIELD3 ,A.ICGRKEY AS FIELD4 ,A.ICGRTYPE AS FIELD5 ,C.ICGRNAME AS FIELD6 FROM TWORK_MST_ACXUR A INNER JOIN TWORK_MST_AC B ON A.CTKEY = B.CTKEY AND A.ACKEY = B.ACKEY LEFT OUTER JOIN TWORK_MST_ICGR C ON A.CTKEY = C.CTKEY AND A.OWKEY = C.OWKEY AND A.ICGRKEY = C.ICGRKEY AND A.ICGRTYPE = C.ICGRTYPE LEFT OUTER JOIN TADMIN_MST_UR D ON A.URKEY = D.URKEY AND A.CTKEY = D.CTKEY WHERE 1 = 1
AND A.LOGGRPCD IN
#{LOGGRPCD_SELECTION_VALUE}
AND A.CTKEY IN
#{CTKEY_AUTH_LIST}
AND ( A.URKEY LIKE '%' || #{value} || '%' OR A.ACKEY LIKE '%'|| #{value} || '%' OR B.ACNAME LIKE '%'|| #{value} || '%' OR A.ICGRKEY LIKE '%'|| #{value} || '%' OR A.ICGRTYPE LIKE '%'|| #{value} || '%' OR C.ICGRNAME LIKE '%'|| #{value} || '%' OR D.URNM LIKE '%'|| #{value} || '%' )

SELECT A.ICKEY AS FIELD1 ,B.ICNM AS FIELD2 ,A.OWKEY AS FIELD3 ,B.ICUNITKEY AS FIELD4 ,B.UOM AS FIELD5 ,'ICUTTYPE' || ';' || B.UOM AS FIELD5_DESC ,A.CP AS FIELD6 ,A.ICGRPKEY AS FIELD7 ,B.SPEC AS FIELD8 ,A.LOGGRPCD AS FIELD9 ,A.DCKEY AS FIELD10 FROM ( SELECT OWKEY, ICKEY, LOGGRPCD, DCKEY, ICGRPKEY, MAX(CP) AS CP FROM TADMIN_MST_ICXCT WHERE ICGRPKEY IN ('19', '20', '21') GROUP BY OWKEY, ICKEY, LOGGRPCD, DCKEY, ICGRPKEY ) A INNER JOIN TADMIN_MST_IC B ON A.OWKEY = B.OWKEY AND A.ICKEY = B.ICKEY WHERE B.CLOSDATE >= #{sysdate} AND B.DELYN = 'N'
AND A.OWKEY = #{owkey}
AND A.ICKEY = #{ickey}
AND A.OWKEY IN
#{OWKEY_AUTH_LIST}
AND (A.OWKEY LIKE '%'|| #{value} || '%' OR A.ICKEY LIKE '%'|| #{value} || '%' OR B.ICNM LIKE '%'|| #{value} || '%' OR B.ICUNITKEY LIKE '%'|| #{value} || '%' OR B.UOM LIKE '%'|| #{value} || '%' )

